#![allow(clippy::unwrap_used, clippy::expect_used, clippy::doc_markdown)]

use mqo_eval::{
    summary::summarize,
    types::{QuestionResult, Verdict},
};

#[test]
fn acceptance_ac7() {
    // Build a minimal result set and serialize stats to JSON.
    let results = vec![QuestionResult {
        question: "Q".to_owned(),
        id: "q1".to_owned(),
        verdict: Verdict::Correct,
        confidence: 0.9,
        pillars_fired: vec![],
        latency_ms: 50,
    }];

    let stats = summarize(&results);
    let json = serde_json::to_value(&stats).expect("stats must be serializable");

    // Required mcp-eval-compatible field names.
    assert!(
        json.get("accuracy").is_some(),
        "summary JSON must contain 'accuracy' field"
    );
    assert!(
        json.get("no_bind_rate").is_some(),
        "summary JSON must contain 'no_bind_rate' field"
    );
    assert!(
        json.get("mean_latency_ms").is_some(),
        "summary JSON must contain 'mean_latency_ms' field"
    );
    // Additional fields present.
    assert!(json.get("mean_confidence").is_some());
    assert!(json.get("total").is_some());
}
